</a>Generated URL
/student/101?name=Rushikesh&course=Angular14. Read Query Parameters
student-details.component.ts
1st way
import { Component } from '@angular/core';
import { ActivatedRoute } from '@angular/router';@Component({
selector:'app-student-details',
standalone:true,
templateUrl:'./student-details.component.html'
})
export class StudentDetailsComponent{
studentId='';
studentName='';
course='';
constructor(private route:ActivatedRoute){
this.studentId=this.route.snapshot.paramMap.get('id')!;
this.studentName=this.route.snapshot.queryParamMap.get('name')!;
this.course=this.route.snapshot.queryParamMap.get('course')!;
}
}
2nd way
import { Component } from '@angular/core';
import { ActivatedRoute } from '@angular/router';@Component({
selector: 'app-student-details',
standalone: true,
templateUrl: './student-details.component.html'
})
export class StudentDetailsComponent {
studentId = '';
studentName = '';
course = '';
constructor(private route: ActivatedRoute) {
// Listen for Route Parameter changes
this.route.paramMap.subscribe(params => {
this.studentId = params.get('id')!;
});
// Listen for Query Parameter changes
this.route.queryParamMap.subscribe(params => {
this.studentName = params.get('name')!;
this.course = params.get('course')!;
});
}
}
